export function mean(nums) {
  let total = 0;
  for (const n of nums) total += n;
  return total / nums.length;
}

export function variance(nums) {
  let total = 0;
  for (const n of nums) total += n;
  const m = total / nums.length;
  let acc = 0;
  for (const n of nums) acc += (n - m) ** 2;
  return acc / nums.length;
}
